#include<bits/stdc++.h>
using namespace std;
#define int long long

const int N = 1e5 + 5;

int n, m, s;

struct Edge
{
    int v, w;
};
vector<Edge> e[N];

int dis[N], sum[N];
bool vis[N];

void Dijkstra()
{
    memset(dis, 0x3f, sizeof dis);
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> q;
    q.push({0, s});
    dis[s] = 0, sum[s] = 1;
    while(!q.empty())
    {
        auto [d, u] = q.top();
        q.pop();
        if(vis[u]) continue;
        vis[u] = 1;
        for(auto [v, w] : e[u])
        {
            if(dis[v] > dis[u] + w)
            {
                dis[v] = dis[u] + w;
                sum[v] = sum[u];
                q.push({dis[v], v});
            }
            else if(dis[v] == dis[u] + w)
            {
                sum[v] += sum[u];
            }
        }
    }
}

signed main()
{
    cin.tie(0) -> sync_with_stdio(0);
    cin >> n >> m;
    s = 1;
    for(int i = 1; i <= m; i++)
    {
        int u, v, w;
        cin >> u >> v >> w;
        e[u].push_back({v, w});
    }
    Dijkstra();
    if(dis[n] > 1e18) cout << "No answer";
    else cout << dis[n] << ' ' << sum[n];
    return 0;
}
